import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import AlertToast from "./AlertToast";
import BusCharts from "./BusCharts";

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [filter, setFilter] = useState("All");
  const [lastUpdated, setLastUpdated] = useState(null);
  const [trendData, setTrendData] = useState([]);

  const fetchBuses = async () => {
    try {
      const res = await fetch("http://127.0.0.1:8000/buses");
      const data = await res.json();
      setBuses(data.buses || []);
      setLastUpdated(new Date(data.last_updated * 1000).toLocaleTimeString());
      setTrendData(data.recent_buses.map((d, i) => ({
        time: `T-${data.recent_buses.length - i}`,
        Running: d.filter(b => b.status === "Running").length,
        Ghost: d.filter(b => b.status === "Ghost").length,
        Anomaly: d.filter(b => b.status === "Anomaly").length
      })));
    } catch (err) {
      console.error("Error fetching buses:", err);
    }
  };

  // Fetch initially and every 2 minutes
  useEffect(() => {
    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // 2 min
    return () => clearInterval(interval);
  }, []);

  const runningCount = buses.filter((b) => b.status === "Running").length;
  const ghostCount = buses.filter((b) => b.status === "Ghost").length;
  const anomalyCount = buses.filter((b) => b.status === "Anomaly").length;

  const filteredBuses =
    filter === "All"
      ? buses
      : buses.filter((b) =>
          filter === "Running"
            ? b.status === "Running"
            : filter === "Ghost"
            ? b.status === "Ghost"
            : b.status === "Anomaly"
        );

  return (
    <div style={{ height: "100vh", width: "100%", position: "relative" }}>
      {/* Filter */}
      <div
        style={{
          position: "absolute",
          top: 12,
          left: 50,
          background: "rgba(255,255,255,0.95)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        <label>
          Show:{" "}
          <select value={filter} onChange={(e) => setFilter(e.target.value)}>
            <option value="All">All</option>
            <option value="Running">Running</option>
            <option value="Ghost">Ghost</option>
            <option value="Anomaly">Anomaly</option>
          </select>
        </label>
      </div>

      {/* Counts */}
      <div
        style={{
          position: "absolute",
          bottom: 10,
          left: 10,
          background: "rgba(255,255,255,0.9)",
          padding: "8px 12px",
          borderRadius: "8px",
          boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
          zIndex: 1000,
          fontSize: "14px",
        }}
      >
        🟢 Running: {runningCount} <br />
        🔴 Ghost: {ghostCount} <br />
        🟠 Anomaly: {anomalyCount} <br />
        ⏰ Last updated: {lastUpdated}
      </div>

      {/* Map */}
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={12}
        style={{ height: "100%", width: "100%" }}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          subdomains={["a", "b", "c", "d"]}
        />

        {filteredBuses.map((bus, index) => (
          <CircleMarker
            key={`${bus.feed}-${bus.id}-${index}`}
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={
              bus.status === "Running"
                ? "green"
                : bus.status === "Ghost"
                ? "red"
                : "orange"
            }
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Feed:</strong> {bus.feed} <br />
                <strong>Status:</strong> {bus.status} <br />
                <strong>Speed:</strong>{" "}
                {bus.speed ? bus.speed.toFixed(1) + " mph" : "N/A"}
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>

      {/* Alerts */}
      <AlertToast buses={buses} />

      {/* Charts */}
      <div
        style={{
          position: "absolute",
          top: 80,
          left: 50,
          zIndex: 1000,
          background: "rgba(255,255,255,0.95)",
          padding: "8px",
          borderRadius: "8px",
        }}
      >
        <BusCharts trendData={trendData} />
      </div>
    </div>
  );
}
